when.set-body:
@{
                    var jo = context.Response.Body.As<JObject>();
                    var arr = jo["value"] as JArray;
                    if (arr == null || arr.Count == 0) {
                        return new JObject(new JProperty("found", false)).ToString();
                    }
                    var c = (JObject)arr[0];
                    var result = new JObject(
                        new JProperty("found", true),
                        new JProperty("customerAccount", c.Value<string>("CustomerAccount")),
                        new JProperty("name", c.Value<string>("OrganizationName")),
                        new JProperty("dataAreaId", c.Value<string>("dataAreaId")),
                        new JProperty("currency", c.Value<string>("SalesCurrencyCode")),
                        new JProperty("customerGroup", c.Value<string>("CustomerGroupId")),
                        new JProperty("paymentTerms", c.Value<string>("PaymentTerms")),
                        new JProperty("email", c.Value<string>("PrimaryContactEmail")),
                        new JProperty("phone", c.Value<string>("PrimaryContactPhone")),
                        new JProperty("address", new JObject(
                            new JProperty("street", c.Value<string>("AddressStreet")),
                            new JProperty("city", c.Value<string>("AddressCity")),
                            new JProperty("zipCode", c.Value<string>("AddressZipCode")),
                            new JProperty("state", c.Value<string>("AddressState")),
                            new JProperty("countryRegionId", c.Value<string>("AddressCountryRegionId")),
                            new JProperty("countryISO", c.Value<string>("AddressCountryRegionISOCode"))
                        ))
                    );
                    return result.ToString();
                }
